declare STAT_HOST="https://streak-stats.demolab.com"
declare -A STAT_ATTRIBUTES=(
    [background]='0,000000,110022,111133,111133,111133'
    [border_radius]=30
    [currStreakLabel]=1177DD
    [currStreakNum]=FF0044
    [card_width]=190
    [dates]=8866EE
    [excludeDaysLabel]=EB5454
    [fire]=1177DD
    [hide_border]=true
    [mode]=weekly
    [ring]=5522CC
    [sideLabels]=1177DD
    [sideNums]=44BBFF
    [src]=https://streak-stats.demolab.com
    [stroke]=5522CC94
    [theme]=dark-minimalist
    [user]=metaory
)
    # [width]=140
    # [width]='45%'
declare -A IMG_ATTRIBUTES=(
    [height]='150'
    [width]=160
)

echo ":: ${STAT_ATTRIBUTES[*]} ::"

declare -a STAT_TYPES=(current_streak longest_streak total_contributions)

cat << EOF >> README.md
<img align="left" height="150" src="https://github-readme-stats.vercel.app/api?username=metaory&ring_color=5522CC&bg_color=45,110022,110022,110022,110011,100010,000000&text_color=44BBFF&border_radius=30&hide_title=true&hide_rank=false&show_icons=true&include_all_commits=true&count_private=true&disable_animations=false&locale=en&hide_border=true"  alt="stats graph" />
EOF

for ST in "${STAT_TYPES[@]}"; do
    printf '<img\n\talt="%s"\n' "$ST" >> README.md

    for IA in "${!IMG_ATTRIBUTES[@]}"; do
        printf '\t%s="%s"\n' "$IA" "${IMG_ATTRIBUTES[${IA}]}" >> README.md
    done

    printf '\tsrc="%s?' "$STAT_HOST" >> README.md

    for SA in "${!STAT_ATTRIBUTES[@]}"; do
        printf '%s=%s&' "$SA" "${STAT_ATTRIBUTES[${SA}]}" >> README.md
    done

    for STT in "${STAT_TYPES[@]}"; do
        # echo "$ST::: STT $STT"
        [ "$ST" != "$STT" ] && \
            printf 'hide_%s=true&' "$STT" >> README.md
    done
    echo

    printf '"\n/>\n' >> README.md
done




